VALUES
  ('judicial-57112235-moex-00617', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人於執行中死亡，按監獄行刑法之相關規定，下列敘述何者正確？', '["監獄應即通知家屬或最近親屬。家屬或最近親屬有數人者，應通知所有人", "監獄應逕報法院指派法官相驗", "監獄應檢附相關資料，陳報法務部", "死亡者之屍體，經相驗並通知後7日內無人請領或無法通知者，得火化之，並存放於骨灰存放設施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00618', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關為維護監獄秩序及安全，出入戒護區者應加辨識之規定，下列敘述何者正確？', '["監獄得要求委外包商穿著一定之外衣，以利人員辨識", "監獄得要求受刑人穿著一定之外衣，以利人員辨識", "監獄得要求參觀訪問者穿著一定之外衣，以利人員辨識", "監獄得要求職員穿著一定之外衣，以利人員辨識"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00619', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄定期舉行之環境衛生檢查，根據監獄行刑法施行細則第41條之規定，下列敘述何者正確？', '["其期間由各監獄依當地狀況定之，每年不得少於2次", "其期間由各監獄依當地狀況定之，每年不得少於1次", "其期間由各監獄依當地狀況定之，每2年1次", "其期間由各監獄依當地狀況定之，每3年1次"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00620', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法施行細則第5條規定，下列何者是指以監內建築物、同一建築物之不同樓層或圍牆隔離 的監禁方式？', '["分別監禁", "嚴為分界", "分界監禁", "分界收容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00621', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄實施分區管教之規定，下列敘述何者正確？', '["監獄不得按監內設施情形，劃分區域實施分區管教", "由監內教化、作業、戒護及相關人員組成分區教輔小組執行之", "分區教輔小組應每2個月開會一次", "監獄應每半年邀集分區教輔小組，舉行全監聯合教輔小組會議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00622', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為協助受刑人復歸社會及落實行社會化之理念，監獄行刑法第29條及受刑人外出實施辦法第4條訂 有外出之規定，使受刑人符合相關事由時，可申請外出，前揭之外出事由不包括下列何者？', '["參加由教育主管機關或其授權單位統一舉辦之各級學校入學考試，取得就學資格而須至監外就讀", "前往外部企業或工廠進行監外作業", "參與公益服務工作方案", "外出參與家庭支持或物質濫用者復健方案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00623', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人甲於炊場作業致死亡，有關給予下列各種協助措施，何者正確？', '["發給死亡補償金新臺幣100萬元", "發給醫療補償金新臺幣30萬元", "死亡者，機關應通知所有五親等內親屬領受補償金", "補償金由最近親屬領受時，應按收容人之配偶、父母、直系血親卑親屬之順序發給之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00624', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄實施移入違規舍懲罰之方式，下列敘述何者錯誤？', '["因借提或移監至其他監獄時，尚未執行日數不得由移入監獄接續執行", "增加個別輔導頻率，促進其遵守紀律", "拒絕受刑人申請購買收音機", "執行期間按日填寫受刑人移入違規舍觀察紀錄表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00625', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依行刑累進處遇條例與外役監條例受刑人縮短刑期之規定，下列敘述何者錯誤？', '["依行刑累進處遇條例之規定，累進處遇進至第三級以上之有期徒刑受刑人，每月成績總分在10分 以上者，得依規定縮短其應執行之刑期", "依外役監條例規定，受刑人經遴選至外役監執行者，除到監之當月，仍依行刑累進處遇條例之規定 縮短刑期外，自到監之翌月起，每執行1個月均得依規定縮短其應執行之刑期", "依行刑累進處遇條例之規定，第三級受刑人，每月成績總分在10分以上者，每執行1個月縮短刑 期2日", "依外役監條例規定，第四級或未編級受刑人，每月縮短刑期2日，第三級受刑人，每月縮短刑期4日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00626', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法及其施行細則對於作業之相關規定，下列敘述何者正確？', '["受刑人從事炊事、打掃、營繕、看護及其他由監獄指定之事務，視同作業", "監獄僅得依監獄行刑法第34條及相關法令規定，承攬公立機關（構）之勞務或成品產製", "監獄辦理自營、委託加工、承攬、指定監外作業或其他作業，應組成自營作業成品及勞務承攬評價 會議，評估相關價格，報監督機關核定後為之", "受刑人因作業或職業訓練致受傷、罹病、重傷、失能或死亡者，應發給勞作金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
